const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;

function esc(v) {
  return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'";
}

const query1 = `SELECT COUNT(*) as total_sent, COALESCE(SUM(envoyes), 0) as total_envoyes, COALESCE(SUM(ouverts), 0) as total_ouverts, COALESCE(SUM(cliques), 0) as total_cliques, COALESCE(SUM(bounces), 0) as total_bounces, COALESCE(SUM(desabonnes), 0) as total_desabonnes FROM newsletter_campaigns WHERE tenant_id = ${esc(tenantId)}`;
const query2 = `SELECT name, subject, (CAST(ouverts as FLOAT) / NULLIF(envoyes, 0) * 100) as open_rate, (CAST(cliques as FLOAT) / NULLIF(envoyes, 0) * 100) as click_rate FROM newsletter_campaigns WHERE tenant_id = ${esc(tenantId)} ORDER BY open_rate DESC NULLS LAST LIMIT 5`;
const query3 = `SELECT DATE_TRUNC('month', created_at)::DATE as month, COUNT(*) as campaign_count, COALESCE(SUM(envoyes), 0) as total_envoyes FROM newsletter_campaigns WHERE tenant_id = ${esc(tenantId)} AND created_at >= NOW() - INTERVAL '6 months' GROUP BY DATE_TRUNC('month', created_at) ORDER BY month DESC`;
const query4 = `SELECT COUNT(*) as count FROM subscribers WHERE tenant_id = ${esc(tenantId)} AND status = 'active'`;

return { queries: [query1, query2, query3, query4] };

const aggregateData = $('05. Query Aggregate Stats').first().json || [];
const bestCampaignsData = $('06. Query Best Campaigns').first().json || [];
const monthlySendsData = $('07. Query Monthly Sends').first().json || [];
const activeSubscribersData = $('08. Query Active Subscribers').first().json || [];

const aggregateStats = (Array.isArray(aggregateData) && aggregateData.length > 0) ? aggregateData[0] : {};

const totalSent = parseInt(aggregateStats.total_sent) || 0;
const totalEnvoyes = parseInt(aggregateStats.total_envoyes) || 0;
const totalOuverts = parseInt(aggregateStats.total_ouverts) || 0;
const totalCliques = parseInt(aggregateStats.total_cliques) || 0;

const avgOpenRate = totalEnvoyes > 0 ? (totalOuverts / totalEnvoyes * 100).toFixed(2) : 0;
const avgClickRate = totalEnvoyes > 0 ? (totalCliques / totalEnvoyes * 100).toFixed(2) : 0;

const bestCampaigns = Array.isArray(bestCampaignsData) ? bestCampaignsData.map(row => ({
  name: row.name,
  subject: row.subject,
  openRate: parseFloat(row.open_rate || 0).toFixed(2),
  clickRate: parseFloat(row.click_rate || 0).toFixed(2)
})) : [];

const monthlySends = Array.isArray(monthlySendsData) ? monthlySendsData.map(row => ({
  month: row.month,
  campaignCount: parseInt(row.campaign_count) || 0,
  totalEnvoyes: parseInt(row.total_envoyes) || 0
})) : [];

const totalActiveSubscribers = (Array.isArray(activeSubscribersData) && activeSubscribersData.length > 0) ? parseInt(activeSubscribersData[0].count) || 0 : 0;

const formatted = {
  analytics: {
    totalSent: totalSent,
    totalEnvoyes: totalEnvoyes,
    totalOuverts: totalOuverts,
    totalCliques: totalCliques,
    avgOpenRate: parseFloat(avgOpenRate),
    avgClickRate: parseFloat(avgClickRate),
    bestCampaigns: bestCampaigns,
    monthlySends: monthlySends,
    totalActiveSubscribers: totalActiveSubscribers
  }
};

return formatted;
